            var parameter = result.Value.parametros.First();
            parameter.ParameterName.Should().Be($"@{DBSMSAliceDicInfo.DtCad}");
            parameter.Value.Should().BeOfType<DateTime>();
            var expectedDate = DateTime.Parse(testDate);
            ((DateTime)parameter.Value).Should().Be(expectedDate);
            result.Value.where.Should().Contain($"CONVERT(DATE,[{DBSMSAliceDicInfo.PTabelaNome}].[{DBSMSAliceDicInfo.DtCad}], 103) = CONVERT(DATE, @{DBSMSAliceDicInfo.DtCad}, 103)");
